prompt.task:
=== P0-1: save_current_topic (agent.py, return 前) ===

if self._persistence and intent and intent not in ("general", "suggest_options", "suggest"):
    self._persistence.save_current_topic(intent)

=== P0-2: save_learning_goal (agent.py, return 前) ===

if self._persistence and intent not in ("general", "suggest_options", "suggest"):
    old = self._persistence.load_learning_goal()
    if not old:
        self._persistence.save_learning_goal(intent)

=== P0-3: save_goal_progress (agent.py, return 前) ===

if self._persistence and self.diagnostic_engine:
    summary = self.diagnostic_engine.get_mastery_summary()
    skills = summary.get("skills", {})
    if skills:
        avg = sum(skills.values()) / max(len(skills), 1)
        self._persistence.save_goal_progress(avg)

=== P1-4: select_topic_by_mastery (agent.py, compose 调用前) ===

# 根据掌握度最低的技能自动选择教学话题
try:
    if self.diagnostic_engine:
        summary = self.diagnostic_engine.get_mastery_summary()
        skills = summary.get("skills", {})
        if skills:
            weakest = PolicyComposer._select_topic_by_mastery({"skills": skills})
            if weakest and intent == "general":
                intent = weakest
except Exception:
    pass

=== P1-5: adjust_difficulty (agent.py, return 前) ===

if self._persistence and self.diagnostic_engine:
    summary = self.diagnostic_engine.get_mastery_summary()
    recent = summary.get("recent_history", [])
    if recent:
        correct_count = sum(1 for r in recent if r.get("correct"))
        rate = correct_count / max(len(recent), 1)
        new_level = self._persistence.adjust_difficulty(rate)
        if new_level:
            _logger.info("Phase 29: difficulty adjusted to %s", new_level)

=== P2-6: save_topics (agent.py, return 前) ===

if self._persistence and intent not in ("general", "suggest_options", "suggest"):
    old_topics = self._persistence.load_topics()
    if intent not in old_topics:
        self._persistence.save_topics(old_topics + [intent])

=== P2-7: mastery_snapshot API (schemas.py + dashboard.py) ===

2a. api/models/schemas.py UserDashboardResponse 新增:

