    session_id: str
    ttm_radar: TTMRadarData
    sdt_rings: SDTRingsData
    progress: ProgressData
    mastery_snapshot: dict | None = None  # Phase 29

2b. api/routers/dashboard.py get_user_dashboard return 前:

try:
    from api.services.dashboard_aggregator import DashboardAggregator
    snap = DashboardAggregator.get_mastery_snapshot(session_id)
except Exception:
    snap = None
return UserDashboardResponse(
    session_id=session_id,
    ttm_radar=TTMRadarData(**ttm_data),
